mapper.sql:
SELECT ICKEY
     , MAX(BOXLENGTH) AS BOXLENGTH, MAX(BOXWIDTH) AS BOXWIDTH, MAX(BOXHEIGHT) AS BOXHEIGHT, MAX(BOXSIZEUNIT) AS BOXSIZEUNIT, MAX(BOXWEIGHT) AS BOXWEIGHT, MAX(BOXWEIGHTUNIT) AS BOXWEIGHTUNIT, MAX(BOXVOLUME) AS BOXVOLUME, MAX(BOXVOLUMEUNIT) AS BOXVOLUMEUNIT
     , MAX(BOLLENGTH) AS BOLLENGTH, MAX(BOLWIDTH) AS BOLWIDTH, MAX(BOLHEIGHT) AS BOLHEIGHT, MAX(BOLSIZEUNIT) AS BOLSIZEUNIT, MAX(BOLWEIGHT) AS BOLWEIGHT, MAX(BOLWEIGHTUNIT) AS BOLWEIGHTUNIT, MAX(BOLVOLUME) AS BOLVOLUME, MAX(BOLVOLUMEUNIT) AS BOLVOLUMEUNIT
     , MAX(EALENGTH) AS EALENGTH, MAX(EAWIDTH) AS EAWIDTH, MAX(EAHEIGHT) AS EAHEIGHT, MAX(EASIZEUNIT) AS EASIZEUNIT, MAX(EAWEIGHT) AS EAWEIGHT, MAX(EAWEIGHTUNIT) AS EAWEIGHTUNIT, MAX(EAVOLUME) AS EAVOLUME, MAX(EAVOLUMEUNIT) AS EAVOLUMEUNIT
  FROM (
        SELECT ICKEY
             , LENGTH AS BOXLENGTH, WIDTH AS BOXWIDTH, HEIGHT AS BOXHEIGHT, SIZEUNIT AS BOXSIZEUNIT, WEIGHT AS BOXWEIGHT, WEIGHTUNIT AS BOXWEIGHTUNIT, VOLUME AS BOXVOLUME, VOLUMEUNIT AS BOXVOLUMEUNIT
             , 0 AS BOLLENGTH, 0 AS BOLWIDTH, 0 AS BOLHEIGHT, NULL AS BOLSIZEUNIT, 0 AS BOLWEIGHT, NULL AS BOLWEIGHTUNIT, 0 AS BOLVOLUME, NULL AS BOLVOLUMEUNIT
             , 0 AS EALENGTH, 0 AS EAWIDTH, 0 AS EAHEIGHT, NULL AS EASIZEUNIT, 0 AS EAWEIGHT, NULL AS EAWEIGHTUNIT, 0 AS EAVOLUME, NULL AS EAVOLUMEUNIT
          FROM TADMIN_INTF_ICUNIT
         WHERE INTERFACE_ID = #{interfaceId}
           AND REQUESTDT = #{requestDt} 
           AND UOM = #{boxuom}

        UNION ALL

        SELECT ICKEY
             , 0 AS BOXLENGTH, 0 AS BOXWIDTH, 0 AS BOXHEIGHT, NULL AS BOXSIZEUNIT, 0 AS BOXWEIGHT, NULL AS BOXWEIGHTUNIT, 0 AS BOXVOLUME, NULL AS BOXVOLUMEUNIT
             , LENGTH AS BOLLENGTH, WIDTH AS BOLWIDTH, HEIGHT AS BOLHEIGHT, SIZEUNIT AS BOLSIZEUNIT, WEIGHT AS BOLWEIGHT, WEIGHTUNIT AS BOLWEIGHTUNIT, VOLUME AS BOLVOLUME, VOLUMEUNIT AS BOLVOLUMEUNIT
             , 0 AS EALENGTH, 0 AS EAWIDTH, 0 AS EAHEIGHT, NULL AS EASIZEUNIT, 0 AS EAWEIGHT, NULL AS EAWEIGHTUNIT, 0 AS EAVOLUME, NULL AS EAVOLUMEUNIT
          FROM TADMIN_INTF_ICUNIT
         WHERE INTERFACE_ID = #{interfaceId}
           AND REQUESTDT = #{requestDt} 
           AND UOM = #{boluom}

        UNION ALL

        SELECT ICKEY
             , 0 AS BOXLENGTH, 0 AS BOXWIDTH, 0 AS BOXHEIGHT, NULL AS BOXSIZEUNIT, 0 AS BOXWEIGHT, NULL AS BOXWEIGHTUNIT, 0 AS BOXVOLUME, NULL AS BOXVOLUMEUNIT
             , 0 AS BOLLENGTH, 0 AS BOLWIDTH, 0 AS BOLHEIGHT, NULL AS BOLSIZEUNIT, 0 AS BOLWEIGHT, NULL AS BOLWEIGHTUNIT, 0 AS BOLVOLUME, NULL AS BOLVOLUMEUNIT
             , LENGTH AS EALENGTH, WIDTH AS EAWIDTH, HEIGHT AS EAHEIGHT, SIZEUNIT AS EASIZEUNIT, WEIGHT AS EAWEIGHT, WEIGHTUNIT AS EAWEIGHTUNIT, VOLUME AS EAVOLUME, VOLUMEUNIT AS EAVOLUMEUNIT
          FROM TADMIN_INTF_ICUNIT
         WHERE INTERFACE_ID = #{interfaceId}
           AND REQUESTDT = #{requestDt} 
           AND UOM = #{eauom}
       ) T     
 GROUP BY T.ICKEY
